import{_ as i,o as d,c as e,a2 as s}from"./chunks/framework.DvFsUg-r.js";const p=JSON.parse('{"title":"VuGrid 그리드를 블로그·에이전트에 반입하기","description":"","frontmatter":{"slug":"vugrid-integration","title":"VuGrid 그리드를 블로그·에이전트에 반입하기","authors":[],"tags":["vugrid","grid","vendoring","docusaurus","spec-kit"],"created":"2026-05-30 14:26 (KST)","date":"2026-05-30T05:26:00.000Z"},"headers":[],"relativePath":"journal/2026-05-30-vugrid-integration.md","filePath":"journal/2026-05-30-vugrid-integration.md","lastUpdated":1781092690000}'),r={name:"journal/2026-05-30-vugrid-integration.md"};function a(l,t,o,n,g,h){return d(),e("div",null,[...t[0]||(t[0]=[s(`<p>별도 저장소에서 만든 데이터그리드 <strong>VuGrid</strong> 의 build 산출물을 이 저장소로 <strong>반입(vendoring)</strong> 해, 블로그와 에이전트 양쪽에서 쓸 수 있게 했다. 설계는 spec-kit(<code>specs/003-vugrid-grid-integration</code>)으로 진행했고, 이 글이 곧 블로그 쪽 <strong>동작 데모</strong>다.</p><blockquote><p>이 글은 원래 Docusaurus 에서 <code>&lt;VuGrid&gt;</code> React 컴포넌트로 라이브 그리드를 임베드했다. VitePress 이관(feature 007) 후에는 라이브 임베드 대신 아래의 정적 표와 <a href="/specs/003-vugrid-grid-integration/spec">명세</a> 링크로 대체한다.</p></blockquote><h2 id="핵심-결정" tabindex="-1">핵심 결정 <a class="header-anchor" href="#핵심-결정" aria-label="Permalink to &quot;핵심 결정&quot;">​</a></h2><ul><li><strong>단일 출처</strong> <code>vendor/vugrid/</code> 한 곳에 반입(<code>scripts/sync-vugrid.ps1</code>). 블로그· 에이전트가 같은 파일을 소비한다(리포 사본 없음).</li><li>블로그(Docusaurus=React)는 그리드를 <strong><code>&lt;iframe&gt;</code> 안에서</strong> 띄운다. VuGrid 본문 행은 사이트 전역 CSS 에 취약해, iframe 으로 격리해 <strong>vugrid 스타일시트만</strong> 적용되게 했다.</li><li>양쪽 표면 모두 <strong>정적 서빙(<code>/vugrid/**</code>) + import map</strong> 으로 통일. 코어가 외부화한 런타임 의존 <strong>mitt</strong> 는 <code>_deps/mitt.js</code> 로 동봉한다.</li><li>그리드는 브라우저 전용이라 컴포넌트를 <code>&lt;BrowserOnly&gt;</code> 로 감쌌다.</li></ul><h2 id="데모-—-10행-×-5열" tabindex="-1">데모 — 10행 × 5열 <a class="header-anchor" href="#데모-—-10행-×-5열" aria-label="Permalink to &quot;데모 — 10행 × 5열&quot;">​</a></h2><p>아래는 <code>@site/src/components/VuGrid</code> 컴포넌트에 컬럼 정의와 행 데이터를 넘긴 것이다.</p><table tabindex="0"><thead><tr><th style="text-align:right;">ID</th><th>이름</th><th>팀</th><th>역할</th><th style="text-align:right;">점수</th></tr></thead><tbody><tr><td style="text-align:right;">1</td><td>홍길동</td><td>플랫폼</td><td>개발</td><td style="text-align:right;">92</td></tr><tr><td style="text-align:right;">2</td><td>김철수</td><td>플랫폼</td><td>개발</td><td style="text-align:right;">88</td></tr><tr><td style="text-align:right;">3</td><td>이영희</td><td>데이터</td><td>분석</td><td style="text-align:right;">95</td></tr><tr><td style="text-align:right;">4</td><td>박민수</td><td>데이터</td><td>엔지니어</td><td style="text-align:right;">81</td></tr><tr><td style="text-align:right;">5</td><td>최지우</td><td>디자인</td><td>UX</td><td style="text-align:right;">90</td></tr><tr><td style="text-align:right;">6</td><td>정해인</td><td>플랫폼</td><td>SRE</td><td style="text-align:right;">77</td></tr><tr><td style="text-align:right;">7</td><td>강수진</td><td>데이터</td><td>분석</td><td style="text-align:right;">84</td></tr><tr><td style="text-align:right;">8</td><td>윤도현</td><td>디자인</td><td>UI</td><td style="text-align:right;">86</td></tr><tr><td style="text-align:right;">9</td><td>임나라</td><td>플랫폼</td><td>개발</td><td style="text-align:right;">91</td></tr><tr><td style="text-align:right;">10</td><td>서준호</td><td>데이터</td><td>엔지니어</td><td style="text-align:right;">79</td></tr></tbody></table><blockquote><p>위는 원본 라이브 데모(인라인 필터 on)의 데이터다. 라이브 그리드 임베드는 VitePress 이관 후 접었다 — 그리드 구현·동작은 <a href="/specs/003-vugrid-grid-integration/spec">VuGrid 그리드 통합 명세</a> 를 참고한다. (스크린샷이 필요하면 <code>blog/public/img/vugrid-demo.png</code> 에 추가)</p></blockquote><h2 id="사용법" tabindex="-1">사용법 <a class="header-anchor" href="#사용법" aria-label="Permalink to &quot;사용법&quot;">​</a></h2><div class="language-mdx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mdx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> VuGrid </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@site/src/components/VuGrid&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">VuGrid</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> columns</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{[{dataField: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;name&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, headerText: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;이름&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}]}</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">        rows</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{[{name: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;홍길동&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}]} /&gt;</span></span></code></pre></div><p>컴포넌트가 <code>&lt;iframe&gt;</code> 격리와 <code>&lt;BrowserOnly&gt;</code> 래핑을 내장하므로, 문서에서는 컬럼·행(필요 시 <code>gridProps</code>)만 넘기면 된다. 인라인 필터처럼 그리드 옵션은 <code>gridProps</code>(VuGrid <code>create</code> 의 3번째 인자)로 전달한다 — 위 데모는 <code>{showInlineFilter: true, enableFilter: true}</code> 를 켰다.</p><h2 id="삽질-로그" tabindex="-1">삽질 로그 <a class="header-anchor" href="#삽질-로그" aria-label="Permalink to &quot;삽질 로그&quot;">​</a></h2><p>겉보기엔 &quot;빌드 파일 복사&quot;지만, 실제로는 세 번 막혔다.</p><ol><li><strong>본문 셀이 세로로 쌓임</strong> — 처음 반입한 빌드는 본문을 <code>&lt;div&gt;</code> 로 그렸는데 테마 <code>default.css</code> 에 본문 행 가로배치 규칙이 빠져 있었다. 임시로 CSS 를 보강.</li><li><strong>인라인 필터 입력이 사라짐</strong> — 반입한 <code>dist</code> 가 <strong>오래된 빌드</strong>라, 필터 값 유지 로직(<code>inlineFilterState</code>)이 없었다. → vugrid 를 <strong>현재 소스로 재빌드</strong> (<code>vite build</code>)하고 다시 반입.</li><li><strong>본문 행 폭이 40px 로 붕괴</strong> — 재빌드한 새 버전은 본문을 <strong><code>&lt;table&gt;</code> + <code>&lt;colgroup&gt;</code></strong> 으로 그린다(div → table 로 구조가 바뀜). 그런데 1번에서 넣은 CSS 보강(<code>.vugrid-row{display:flex}</code>)이 <code>&lt;tr&gt;</code> 의 <code>display:table-row</code> 를 덮어 테이블을 깼다. → 보강 CSS 제거. 테이블은 colgroup 으로 스스로 정렬된다.</li></ol><p>교훈: <strong>&quot;빌드된 산출물&quot;의 버전·렌더링 구조가 곧 계약이다.</strong> 반입본이 stale 이면 조용히 기능이 빠지고, 한 버전의 구조에 맞춘 패치는 다음 버전을 깬다. 그래서 <code>VENDOR.md</code> 에 출처·버전을, <code>sync-vugrid</code> 로 재반입 절차를 박아 두었다.</p><p>자세한 명세는 <a href="/specs/003-vugrid-grid-integration/spec">VuGrid 그리드 통합 spec</a> 참고.</p>`,16)])])}const u=i(r,[["render",a]]);export{p as __pageData,u as default};
